array_filter(
				$stored_results,
				function ( $url ) use ( $solved ) {
					return ! in_array( $url, $solved );
				},
				ARRAY_FILTER_USE_KEY
			)

array_filter(
			$constants,
			function ( $key ) use ( $needle ) {
				return str_contains( $key, $needle );
			},
			ARRAY_FILTER_USE_KEY
		)

array_filter(
			$old_values,
			function ( $key ) {
				return in_array( $key, $this->stale_cache_options, true );
			},
			ARRAY_FILTER_USE_KEY
		)

array_filter(
			$values,
			function ( $key ) {
				return in_array( $key, $this->stale_cache_options, true );
			},
			ARRAY_FILTER_USE_KEY
		)

array_filter(
			$links[0],
			function ( $link ) {
				return apply_filters(
					'omgf_frontend_process_parse_links',
					str_contains( $link, 'fonts.googleapis.com/css' ) || str_contains( $link, 'fonts.bunny.net/css' ) || str_contains( $link, 'fonts-api.wp.com/css' ),
					$link
				);
			}
		)

array_filter(
			$resource_hints[0],
			function ( $resource_hint ) {
				preg_match( '/href=[\'"](https?:)?\/\/(.*?)[\'"\/]/', $resource_hint, $url );
				preg_match( '/rel=[\'"](.*?)[ \'"]/', $resource_hint, $attr );

				if ( empty( $url[2] ) || empty( $attr[1] ) ) {
					return false; // @codeCoverageIgnore
				}

				$url  = $url[2];
				$attr = $attr[1];

				return ! empty( preg_grep( "/$url/", self::RESOURCE_HINTS_URLS ) ) && in_array( $attr, self::RESOURCE_HINTS_ATTR );
			}
		)

array_filter( $settings, function ( $row, $constant ) use ( $needles, $ignore ) {
			foreach ( $needles as $needle ) {
				if ( str_starts_with( $constant, $needle ) && ! in_array( $row, $ignore, true ) ) {
					return true;
				}
			}

			return false;
		}, ARRAY_FILTER_USE_BOTH )

wp_remote_get(
			$url,
			[
				/**
				 * Allow WP devs to use a different User-Agent, e.g. for compatibility with older browsers/OSes.
				 *
				 * @filter omgf_optimize_user_agent
				 */ 'user-agent' => apply_filters( 'omgf_optimize_user_agent', self::USER_AGENT['woff2'] ),
			]
		)

